import React, { MouseEvent, ReactElement, RefObject, useEffect, useRef, useState } from 'react';
import './BackgroundCanvas.css';

type MouseCoords = {
  mouseX: number,
  mouseY: number
};

type Point = {
  x: number,
  y: number
};

type Triangle = {
  first: Point,
  second: Point,
  third: Point
};

type Setter<T> = (newValue: T) => void;

const gridSpacing = 50;
const gridColour = '#999';

const onMouseMove = (event: MouseEvent<HTMLCanvasElement>, canvas: HTMLCanvasElement, points: Point[][]) => {
  if (points.length === 0) {
    return;
  }

  const context = canvas.getContext('2d');
  if (context === null) {
    return;
  }

  const { mouseX, mouseY } = getMousePosition(event, canvas);

  context.clearRect(0, 0, canvas.width, canvas.height);
  const gradient = context.createRadialGradient(mouseX, mouseY, 0, mouseX, mouseY, Math.max(mouseX, canvas.width - mouseX));
  gradient.addColorStop(0, '#FFF');
  gradient.addColorStop(0.05, '#FFF');
  gradient.addColorStop(0.2, gridColour);
  gradient.addColorStop(0.9, gridColour);
  gradient.addColorStop(1, gridColour);
  context.strokeStyle = gradient;
  drawMesh(canvas, points);
};

const getMousePosition = (event: MouseEvent<HTMLCanvasElement>, canvas: HTMLCanvasElement): MouseCoords => {
  const rect = canvas.getBoundingClientRect();

  const scaleX = canvas.width / rect.width;
  const scaleY = canvas.height / rect.height;

  const mouseX = (event.clientX - rect.left) * scaleX;
  const mouseY = (event.clientY - rect.top) * scaleY;

  return { mouseX, mouseY };
};

const resizeCanvas = (canvas: HTMLCanvasElement) => {
  canvas.width = window.innerWidth;
  canvas.height = window.innerHeight;
};

const calculateMesh = (canvas: HTMLCanvasElement, setPoints: Setter<Point[][]>) => {
  const offsetLength = canvas.height * Math.tan(Math.PI / 3);
  const offset = Math.ceil(offsetLength / gridSpacing);

  const numPointsX = Math.ceil((canvas.width + offset * gridSpacing) / gridSpacing) + 1;
  const numPointsY = Math.ceil((canvas.height + gridSpacing) / gridSpacing);

  const maxDisplacement = 10;

  const points: Point[][] = [];
  for (let i = 0; i < numPointsX; i++) {
    points[i] = [];
    for (let j = 0; j < numPointsY; j++) {
      const x = i * gridSpacing - offset * gridSpacing;
      const y = j * gridSpacing;
      points[i][j] = {
        x: x + 0.5 * y + randomDisplacement(maxDisplacement),
        y: y + randomDisplacement(10)
      };
    }
  }

  setPoints(points);
};

const randomDisplacement = (max: number): number =>  (Math.random() - 0.5) * 2 * max;

const drawMesh = (canvas: HTMLCanvasElement, points: Point[][]) => {
  const context = canvas.getContext('2d');
  if (context === null) {
    return;
  }

  if (context.strokeStyle === '#000000') {
    context.strokeStyle = gridColour;
  }

  for (let i = 0; i < points.length - 1; i++) {
    for (let j = 0; j < points[0].length - 1; j++) {
      const triangle = {
        first: points[i][j],
        second: points[i + 1][j],
        third: points[i][j + 1]
      };
      drawTriangle(triangle, context);
    }
  }
};

const drawTriangle = (triangle: Triangle, context: CanvasRenderingContext2D) => {
  drawLine(triangle.first, triangle.second, context);
  drawLine(triangle.second, triangle.third, context);
  drawLine(triangle.third, triangle.first, context);
};

const drawLine = (from: Point, to: Point, context: CanvasRenderingContext2D) => {
  context.beginPath();
  context.moveTo(from.x, from.y);
  context.lineTo(to.x, to.y);
  context.stroke();
};

const BackgroundCanvas = (): ReactElement => {
  const canvasRef: RefObject<HTMLCanvasElement> = useRef(null);
  const [points, setPoints] = useState<Point[][]>([]);

  const recalculate = () => {
    if (canvasRef.current != null) {
      const canvas = canvasRef.current;
      resizeCanvas(canvas);
      calculateMesh(canvas, setPoints);
    }
  };

  window.addEventListener('resize', recalculate);
  useEffect(recalculate, [canvasRef]);

  useEffect(() => {
    if (canvasRef.current != null) {
      drawMesh(canvasRef.current, points);
    }
  }, [canvasRef, points]);



  return (<canvas
    ref={canvasRef}
    onMouseMove={(event) => canvasRef.current != null ? onMouseMove(event, canvasRef.current, points) : null}
    className="background-canvas"
  />);
};

export default BackgroundCanvas;
